+/// Encode a CWD path into the session directory name format (mirrors `encode_cwd`
+/// from `src/session.rs`).
+fn encode_cwd_for_test(path: &Path) -> String {
+    let s = path.display().to_string();
+    let s = s.trim_start_matches(['/', '\\']).to_string();
+    let s = s.replace(['/', '\\', ':'], "-");
+    format!("--{s}--")
+}
