+    let start = Instant::now();
+    while tmux.session_exists() {
+        if start.elapsed() > Duration::from_secs(10) {
+            break;
+        }
+        std::thread::sleep(Duration::from_millis(100));
+    }
+
+    if tmux.session_exists() {
+        tmux.send_key("C-d");
+        let start = Instant::now();
+        while tmux.session_exists() {
+            if start.elapsed() > Duration::from_secs(5) {
+                break;
+            }
+            std::thread::sleep(Duration::from_millis(100));
+        }
